  public async validation(
    regPaises: IPaises,
  ): Promise<{ isValid: boolean; message: string } | null> {
    // Validation doesn't use circuit breaker offline fallback (needs real-time check)
    try {
      await this.circuitBreaker.execute(async () => {
        return await axios.post(
          `${this.baseUrl}/validation`,
          regPaises as Paises,
          this.getHeaders(),
        );
      });
      return { isValid: true, message: "Validação bem-sucedida" };
    } catch (error: any) {
      if (error instanceof CircuitBreakerOpenError) {
        return {
          isValid: false,
          message:
            "Serviço temporariamente indisponível. Tente novamente em alguns instantes.",
        };
      }
      if (
        error.response &&
        (error.response.status === 409 || error.response.status === 500)
      ) {
        if (error.response && error.response.data) {
          const { message } = error.response.data;
          const errorMessage = message || "Verifique se o registro já existe!";
          return { isValid: false, message: errorMessage };
        }
      }
      return {
        isValid: false,
        message: "Erro desconhecido ao validar na base.",
      };
    }
  }

